class Solution:
    def reverseVowels(self, s: str) -> str:
        vowels = set('aeiouAEIOU')
        picked = [c for c in s if c in vowels]
        out = []
        for c in s:
            if c in vowels:
                out.append(picked.pop())
            else:
                out.append(c)
        return ''.join(out)

